1	/**
2	 * Full-screen layout wrapper for the onboarding page. Three regions: top
3	 * progress bar, scrollable content (caller-supplied children), and an
4	 * optional pinned composer at the bottom. Auto-scrolls the content region
5	 * to bottom whenever stage- or content-bearing state changes.
6	 */
7	
8	"use client";
9	
10	import type { ReactNode } from "react";
11	import { useEffect, useMemo, useRef } from "react";
12	import BlurStack, { type BlurLayer } from "@/components/ui/blur-stack";
13	import { getProgress, PROGRESS_TOTAL_STEPS } from "../state/derive";
14	import type { OnboardingState, Stage } from "../state/types";
15	import { OnboardingProgress } from "./OnboardingProgress";
16	
17	// Heavy-blur-at-top config — mirror of the default heavy-at-bottom stack.
18	const TOP_BLUR_CONFIG: BlurLayer[] = [
19	  { blur: 0.5, maskStops: [62.5, 75, 87.5, 100], zIndex: 1 },
20	  { blur: 1, maskStops: [50, 62.5, 75, 87.5], zIndex: 2 },
21	  { blur: 2, maskStops: [37.5, 50, 62.5, 75], zIndex: 3 },
22	  { blur: 4, maskStops: [25, 37.5, 50, 62.5], zIndex: 4 },
23	  { blur: 8, maskStops: [12.5, 25, 37.5, 50], zIndex: 5 },
24	  { blur: 16, maskStops: [0, 12.5, 25, 37.5], zIndex: 6 },
25	  { blur: 32, maskStops: [0, 0, 12.5, 25], zIndex: 7 },
26	  { blur: 64, maskStops: [0, 0, 0, 12.5], zIndex: 8 },
27	];
28	
29	interface OnboardingShellProps {
30	  state: OnboardingState;
31	  stage: Stage;
32	  onRestart: () => void;
33	  children: ReactNode;
34	  composer?: ReactNode;
35	}
36	
37	/**
38	 * Single string fingerprint of "what's on screen". Used as a useEffect dep so
39	 * scroll-to-bottom fires once per content change instead of needing 7 deps.
40	 */
41	function getContentFingerprint(state: OnboardingState, stage: Stage): string {
42	  const b = state.server;
43	  // Concat every active progress slot — any change to any stage's status_text
44	  // should re-trigger the scroll-to-bottom effect.
45	  const progress = Object.values(state.progressByStage).join("");
46	  return [
47	    stage,
48	    state.questionIndex,
49	    progress,
50	    state.completedStages.size,
51	    state.ackedWritingStyle ? 1 : 0,
52	    state.ackedTodos ? 1 : 0,
53	    state.workflowsConfirmed ? 1 : 0,
54	    state.platformsConfirmed ? 1 : 0,
55	    state.connectedPlatform ?? "",
56	    b?.writing_style?.style_summary ?? "",
57	    b?.onboarding_todos?.length ?? 0,
58	    b?.suggested_workflows?.length ?? 0,
59	    b?.first_message_conversation_id ?? "",
60	    state.todoExecutionMessage ?? "",
61	  ].join("|");
62	}
63	
64	export function OnboardingShell({
65	  state,
66	  stage,
67	  onRestart,
68	  children,
69	  composer,
70	}: OnboardingShellProps) {
71	  const scrollRef = useRef<HTMLDivElement>(null);
72	  const progressStep = getProgress(state, stage);
73	  const fingerprint = useMemo(
74	    () => getContentFingerprint(state, stage),
75	    [state, stage],
76	  );
77	
78	  useEffect(() => {
79	    scrollRef.current?.scrollTo({
80	      top: scrollRef.current.scrollHeight,
81	      behavior: "smooth",
82	    });
83	  }, [fingerprint]);
84	
85	  return (
86	    <div className="fixed inset-0 z-50 flex flex-col bg-primary-bg backdrop-blur-2xl">
87	      <div
88	        aria-hidden
89	        className="pointer-events-none absolute inset-0 z-0 bg-center bg-cover opacity-40"
90	        style={{
91	          backgroundImage: "url('/images/wallpapers/bands_gradient_black.png')",
92	        }}
93	      />
94	      <OnboardingProgress
95	        currentStep={progressStep}
96	        totalSteps={PROGRESS_TOTAL_STEPS}
97	        onRestart={onRestart}
98	        isRestarting={state.isRestarting}
99	      />
100	
101	      <div
102	        ref={scrollRef}
103	        className="relative z-10 flex-1 overflow-y-auto px-4 pt-20"
104	      >
105	        <div className="relative mx-auto w-full max-w-3xl pb-32">
106	          {children}
107	        </div>
108	      </div>
109	
110	      <BlurStack
111	        className="pointer-events-none fixed top-0 right-0 left-0 z-20 h-24"
112	        config={TOP_BLUR_CONFIG}
113	      />
114	      <BlurStack className="pointer-events-none fixed right-0 bottom-0 left-0 z-20 h-24" />
115	
116	      {composer && (
117	        <div className="fixed inset-x-0 bottom-0 z-30 mx-auto w-full max-w-lg pb-3">
118	          {composer}
119	        </div>
120	      )}
121	    </div>
122	  );
123	}
