import { EASE_OUT_QUART } from "@/features/onboarding/constants/motion";
import { useOnboarding } from "@/features/onboarding/hooks/useOnboarding";
import { useUserStore } from "@/stores/userStore";

const INTRO_FADE_IN = {
  initial: { opacity: 0, filter: "blur(12px)" },
  animate: { opacity: 1, filter: "blur(0px)" },
  transition: { duration: 0.6, ease: EASE_OUT_QUART },
} as const;

const INTRO_SEEN_PREFIX = "gaia.onboarding.introSeen";

// Keyed per-user so a new account still gets the intro, while the same
// user reloading (or coming back from an external OAuth redirect that lands
// them in a fresh browsing context, e.g. Arc's Little Arc) skips it.
function introSeenKey(userId: string): string | null {
  return userId ? `${INTRO_SEEN_PREFIX}.${userId}` : null;
}

function hasSeenIntro(userId: string): boolean {
  if (typeof window === "undefined") return false;
  const key = introSeenKey(userId);
  if (!key) return false;
  try {
    return window.localStorage.getItem(key) === "1";
  } catch {
    return false;
  }
}

function markIntroSeen(userId: string): void {
  const key = introSeenKey(userId);
  if (!key) return;
  try {
    window.localStorage.setItem(key, "1");
  } catch {
    // localStorage unavailable (private mode, etc.) — silently skip.
  }
}

function clearIntroSeen(userId: string): void {
  const key = introSeenKey(userId);
  if (!key) return;
  try {
    window.localStorage.removeItem(key);
  } catch {}
}

export default function Onboarding() {
  const { state, stage, dispatch, restart } = useOnboarding({
    skipAutoRedirect: true,
  });
  const userId = useUserStore((s) => s.userId);
  // Zustand `persist` hydrates from localStorage asynchronously, so on first
  // render `userId` is "" and the seen-marker (keyed by userId) cannot be
  // resolved. Start with `null` (unknown) and resolve once the userId lands
  // — otherwise the intro replays on every reload and after OAuth redirects.
  const [introDone, setIntroDone] = useState<boolean | null>(() =>
    userId ? hasSeenIntro(userId) : null,
  );

  useEffect(() => {
    if (!userId) return;
    setIntroDone((prev) => (prev === null ? hasSeenIntro(userId) : prev));
  }, [userId]);

  const handleRestart = () => {
    clearIntroSeen(userId);
    setIntroDone(false);
    return restart();
  };

  const handleIntroComplete = () => {
    markIntroSeen(userId);
    setIntroDone(true);
  };

  const chat = useChatStage(state, dispatch);

  const stageContent = (() => {
    switch (stage) {
      case "questions":
      case "focus":
      case "processing":
        return null;
      case "revealWriting":
        return <RevealWritingStyle state={state} />;
      case "revealTodos":
        return <RevealTodos state={state} dispatch={dispatch} chat={chat} />;
      case "workflows":
        return <Workflows state={state} dispatch={dispatch} />;
      case "platforms":
        return <Platforms state={state} dispatch={dispatch} />;
      case "chat":
        return <Chat state={state} />;
    }
  })();

  const composer = (() => {
    switch (stage) {
      case "questions":
        return <QuestionsComposer state={state} dispatch={dispatch} />;
      case "focus":
        return <FocusComposer state={state} dispatch={dispatch} />;
      case "processing":
        return null;
      case "revealWriting":
        return <RevealWritingStyleComposer state={state} dispatch={dispatch} />;
      case "revealTodos":
        return null;
      case "workflows":
        return <WorkflowsComposer state={state} dispatch={dispatch} />;
      case "platforms":
        return <PlatformsComposer state={state} dispatch={dispatch} />;
      case "chat":
        return <ChatComposer state={state} />;
    }
  })();

  const wrappedComposer = introDone ? (
    <m.div {...INTRO_FADE_IN}>{composer}</m.div>
  ) : null;

  // While `introDone` is null we don't yet know whether to play the intro
  // (userId hasn't hydrated). Render nothing rather than briefly mounting
