            <CompletedStagesTimeline
              state={state}
              dispatch={dispatch}
              chat={chat}
            />
            {stageContent}
          </m.div>
        ) : null}
      </OnboardingShell>
      <AnimatePresence>
        {introResolved && !introDone && (
          <OnboardingIntro onComplete={handleIntroComplete} />
        )}
      </AnimatePresence>
    </>
  );
}

