          titleWrapper: "py-0",
          content: "px-3 pt-2 pb-3",
        }}
      >
        <AccordionItem
          key={itemKey}
          aria-label={title}
          title={
            <div className="flex items-center gap-2">
              <CheckmarkCircle02Icon className="size-4 text-emerald-500" />
              <span className="text-sm font-medium text-zinc-200">{title}</span>
            </div>
          }
        >
          {children}
        </AccordionItem>
      </Accordion>
    </m.div>
  );
}

