11	interface EmailListProps {
12	  emails?: EmailFetchData[] | null;
13	  backgroundColor?: string;
14	  maxHeight?: string;
15	  isCollapsible?: boolean;
16	  onLoadMore?: () => void;
17	  hasNextPage?: boolean;
18	  isFetchingNextPage?: boolean;
19	}
20	
21	function extractSenderName(from: string): string {
22	  // Extract name before email or use email if no name
23	  const match = from.match(/^"?([^"<]+)"?\s*</);
24	  if (match) {
25	    return match[1].trim();
26	  }
27	
28	  // If no angle brackets, check for name before space
29	  const spaceMatch = from.match(/^([^<]+)\s+</);
30	  if (spaceMatch) {
31	    return spaceMatch[1].trim();
32	  }
33	
34	  // Extract just the email part if no name
35	  const emailMatch = from.match(/<([^>]+)>/);
36	  if (emailMatch) {
37	    return emailMatch[1].split("@")[0];
38	  }
39	
40	  return from.split("@")[0] || from;
41	}
42	
43	function formatTime(time: string | null): string {
44	  if (!time) return "Yesterday";
45	
46	  const date = new Date(time);
47	  const now = new Date();
48	  const diffInHours = (now.getTime() - date.getTime()) / (1000 * 60 * 60);
49	
50	  if (diffInHours < 24) {
51	    return date.toLocaleTimeString("en-US", {
52	      hour: "numeric",
53	      minute: "2-digit",
54	      hour12: true,
55	    });
56	  } else if (diffInHours < 48) {
57	    return "Yesterday";
58	  } else {
59	    return date.toLocaleDateString("en-US", {
60	      month: "short",
61	      day: "numeric",
62	    });
63	  }
64	}
65	
66	export default function EmailListCard({
67	  emails,
68	  backgroundColor = "bg-zinc-800",
69	  maxHeight = "max-h-[300px]",
