74	}: EmailListProps) {
75	  const appendToInput = useAppendToInput();
76	  const sentinelRef = useRef<HTMLDivElement>(null);
77	
78	  useEffect(() => {
79	    if (!onLoadMore || !hasNextPage) return;
80	
81	    const sentinel = sentinelRef.current;
82	    if (!sentinel) return;
83	
84	    const observer = new IntersectionObserver(
85	      (entries) => {
86	        if (entries[0].isIntersecting && !isFetchingNextPage) {
87	          onLoadMore();
88	        }
89	      },
90	      { rootMargin: "300px", threshold: 0 },
91	    );
92	
93	    observer.observe(sentinel);
94	    return () => observer.disconnect();
95	  }, [onLoadMore, hasNextPage, isFetchingNextPage]);
96	
97	  const handleEmailClick = (email: EmailFetchData) => {
