112	        }`}
113	      >
114	        {/* Email List */}
115	        <ScrollShadow className={`${maxHeight} divide-y divide-zinc-800`}>
116	          {!!emails &&
117	            emails.length > 0 &&
118	            emails.map((email) => (
119	              <Tooltip
120	                key={email.id}
121	                content={`Ask about this email from ${extractSenderName(email.from || "Unknown Sender")}`}
122	                showArrow
123	                color="foreground"
124	                delay={0}
125	                closeDelay={0}
126	                disableAnimation
127	              >
128	                <div
129	                  className="group flex cursor-pointer items-center gap-4 p-3 transition-colors hover:bg-zinc-700"
130	                  onClick={() => handleEmailClick(email)}
131	                >
132	                  <div className="w-40 flex-shrink-0">
133	                    <span className="block truncate text-sm font-medium text-gray-300">
134	                      {extractSenderName(email.from || "Unknown Sender")}
135	                    </span>
136	                  </div>
137	
138	                  <div className="min-w-0 flex-1">
139	                    <span className="block truncate text-sm text-white group-hover:text-gray-100">
140	                      {email.subject || "Unknown Subject"}
141	                    </span>
142	                  </div>
143	
144	                  {/* Time */}
